class CountIntervals {

    public CountIntervals() {
        intervals = new TreeSet<>();
    }

    public void add(int left, int right) {
        intervals.add(left);
        intervals.add(right + 1);
    }

    public int count() {
        int count = 0;
        int prev = Integer.MIN_VALUE;
        for (int num : intervals) {
            if (prev < num) {
                count += num - prev - 1;
            }
            prev = num;
        }
        return count;
    }

    private TreeSet<Integer> intervals;
}
```

